import{_ as t,o as h,c as i,a0 as g}from"./chunks/framework.jwovEGr5.js";const e=JSON.parse('{"title":"Thiết lập Hệ thống","description":"","frontmatter":{"title":"Thiết lập Hệ thống"},"headers":[],"relativePath":"system-settings.md","filePath":"system-settings.md"}'),a={name:"system-settings.md"};function o(l,n,s,r,c,u){return h(),i("div",null,[...n[0]||(n[0]=[g('<h1 id="thiet-lap-he-thong" tabindex="-1">Thiết lập Hệ thống <a class="header-anchor" href="#thiet-lap-he-thong" aria-label="Permalink to &quot;Thiết lập Hệ thống&quot;">​</a></h1><p><strong>Thiết lập Hệ thống (System Settings)</strong> trong ABNERP là trung tâm quản lý các cấu hình vận hành cốt lõi của toàn bộ hệ thống. Người dùng có quyền System Manager có thể truy cập các thiết lập này để tùy chỉnh hệ thống theo nhu cầu doanh nghiệp.</p><h2 id="cai-đat-chung" tabindex="-1">Cài đặt chung <a class="header-anchor" href="#cai-đat-chung" aria-label="Permalink to &quot;Cài đặt chung&quot;">​</a></h2><p>Phần <strong>Cài đặt chung</strong> bao gồm các thiết lập cơ bản cho toàn hệ thống:</p><ul><li><strong>Tên hệ thống</strong>: tên hiển thị trong tab trình duyệt và giao diện chính</li><li><strong>URL hệ thống</strong>: địa chỉ trang web của hệ thống</li><li><strong>Logo và Favicon</strong>: hình ảnh đại diện thương hiệu</li><li><strong>Ngôn ngữ mặc định</strong>: giao diện hiển thị sau khi đăng nhập</li><li><strong>Múi giờ</strong>: múi giờ của doanh nghiệp</li><li><strong>Chủ đề màu sắc</strong>: lựa chọn giao diện Light/Dark và màu nhấn</li><li><strong>Hạn mức tải tệp</strong>: kích thước tối đa cho tệp đính kèm và tải lên</li></ul><h2 id="đinh-dang-ngay-so" tabindex="-1">Định dạng ngày/số <a class="header-anchor" href="#đinh-dang-ngay-so" aria-label="Permalink to &quot;Định dạng ngày/số&quot;">​</a></h2><p>Thiết lập định dạng cho phép tùy chỉnh cách hiển thị:</p><ul><li><strong>Định dạng ngày</strong>: DD-MM-YYYY, MM-DD-YYYY, YYYY-MM-DD</li><li><strong>Định dạng giờ</strong>: 12 giờ hoặc 24 giờ</li><li><strong>Dấu phân cách số</strong>: dấu phẩy, dấu chấm, hoặc dấu cách</li><li><strong>Số thập phân</strong>: số chữ số sau dấu thập phân cho tiền tệ và số lượng</li><li><strong>Múi giờ</strong>: hiển thị thời gian theo múi giờ đã chọn</li></ul><h2 id="bao-mat" tabindex="-1">Bảo mật <a class="header-anchor" href="#bao-mat" aria-label="Permalink to &quot;Bảo mật&quot;">​</a></h2><p>Các thiết lập bảo mật bảo vệ hệ thống khỏi truy cập trái phép:</p><ul><li><strong>Xác thực hai yếu tố (2FA)</strong>: bật/tắt và cấu hình 2FA với OTP qua email hoặc ứng dụng authenticator</li><li><strong>Giới hạn đăng nhập</strong>: số lần đăng nhập sai tối đa trước khi khóa tài khoản</li><li><strong>Chính sách mật khẩu</strong>: độ dài tối thiểu, yêu cầu ký tự đặc biệt/chữ hoa/chữ số</li><li><strong>Mã hóa dữ liệu</strong>: cấu hình mã hóa kết nối và dữ liệu nhạy cảm</li><li><strong>IP Cho phép</strong>: danh sách địa chỉ IP được phép truy cập hệ thống</li></ul><h2 id="phien" tabindex="-1">Phiên <a class="header-anchor" href="#phien" aria-label="Permalink to &quot;Phiên&quot;">​</a></h2><p>Quản lý phiên đăng nhập của người dùng:</p><ul><li><strong>Thời gian hết hạn phiên</strong>: thời gian phiên hoạt động trước khi yêu cầu đăng nhập lại</li><li><strong>Giới hạn phiên đồng thời</strong>: số phiên hoạt động tối đa cho một người dùng</li><li><strong>Tự động đăng xuất</strong>: tự động đăng xuất sau một thời gian không hoạt động</li></ul><h2 id="phuong-thuc-đang-nhap" tabindex="-1">Phương thức đăng nhập <a class="header-anchor" href="#phuong-thuc-đang-nhap" aria-label="Permalink to &quot;Phương thức đăng nhập&quot;">​</a></h2><p>ABNERP hỗ trợ nhiều phương thức xác thực:</p><ul><li><strong>Đăng nhập bằng email/mật khẩu</strong>: phương thức mặc định</li><li><strong>Đăng nhập qua mạng xã hội</strong>: Google, Facebook, GitHub</li><li><strong>OAuth</strong>: đăng nhập qua OAuth với các dịch vụ bên thứ ba</li><li><strong>LDAP</strong>: xác thực qua máy chủ LDAP dành cho doanh nghiệp</li><li><strong>SAML</strong>: đăng nhập đơn (Single Sign-On) qua SAML</li></ul><h2 id="file-sao-luu" tabindex="-1">File/Sao lưu <a class="header-anchor" href="#file-sao-luu" aria-label="Permalink to &quot;File/Sao lưu&quot;">​</a></h2><p>Quản lý tệp và sao lưu dữ liệu:</p><ul><li><strong>Kích thước tệp tối đa</strong>: giới hạn dung lượng tệp tải lên</li><li><strong>Loại tệp cho phép</strong>: danh sách định dạng tệp được phép (PDF, DOCX, JPG, PNG, v.v.)</li><li><strong>Tự động xóa tệp tạm</strong>: cấu hình thời gian xóa tệp tạm sau khi sử dụng</li><li><strong>Sao lưu cơ sở dữ liệu</strong>: lên lịch sao lưu tự động, tải về bản sao lưu</li><li><strong>Khôi phục dữ liệu</strong>: công cụ khôi phục từ bản sao lưu</li></ul><p>Việc thiết lập hệ thống đúng đắn ngay từ đầu là nền tảng quan trọng để ABNERP vận hành ổn định, bảo mật và phù hợp với quy trình nghiệp vụ của doanh nghiệp.</p>',21)])])}const d=t(a,[["render",o]]);export{e as __pageData,d as default};
